{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"private_outputs":true,"provenance":[],"authorship_tag":"ABX9TyOOXTGPXZbiYHu+vqxzp4Qf"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["import requests\n","import json\n","import os\n","import time\n","from datetime import datetime\n","\n","# Use the requests library to fetch the top story IDs, then fetch each story's details\n","base_url = \"https://hacker-news.firebaseio.com/v0\"\n","headers = {\"User-Agent\": \"TrendPulse/1.0\"}\n","\n","# categories and keywords\n","categories = {\n","    \"technology\": [\"AI\", \"software\", \"tech\", \"code\", \"computer\", \"data\", \"cloud\", \"API\", \"GPU\", \"LLM\"],\n","    \"worldnews\": [\"war\", \"government\", \"country\", \"president\", \"election\", \"climate\", \"attack\", \"global\"],\n","    \"sports\": [\"NFL\", \"NBA\", \"FIFA\", \"sport\", \"game\", \"team\", \"player\", \"league\", \"championship\"],\n","    \"science\": [\"research\", \"study\", \"space\", \"physics\", \"biology\", \"discovery\", \"NASA\", \"genome\"],\n","    \"entertainment\": [\"movie\", \"film\", \"music\", \"Netflix\", \"game\", \"book\", \"show\", \"award\", \"streaming\"]\n","}\n","\n","collected_data = []\n","category_counts = {cat: 0 for cat in categories}\n","\n","def get_category(title):\n","    title_lower = title.lower()\n","    for category, keywords in categories.items():\n","        for word in keywords:\n","            if word.lower() in title_lower:\n","                return category\n","    return None\n","\n","# folder creation\n","if not os.path.exists('data'):\n","    os.makedirs('data')\n","\n","try:\n","    # Step 1: Fetching top stories\n","    print(\"Fetching top stories...\")\n","    response = requests.get(f\"{BASE_URL}/topstories.json\", headers=HEADERS)\n","    story_ids = response.json()[:500]\n","\n","    # Step 2: each story review\n","    for cat_name in CATEGORIES.keys():\n","        print(f\"Processing category: {cat_name}...\")\n","\n","        for s_id in story_ids:\n","            # A maximum of 25 stories per category only.\n","            if category_counts[cat_name] >= 25:\n","                break\n","\n","            try:\n","                item_res = requests.get(f\"{BASE_URL}/item/{s_id}.json\", headers=HEADERS)\n","                story = item_res.json()\n","\n","                if not story or 'title' not in story:\n","                    continue\n","\n","                assigned_cat = get_category(story['title'])\n","\n","                # Saving the data if the story category matches\n","                if assigned_cat == cat_name:\n","                    story_info = {\n","                        \"post_id\": story.get(\"id\"),\n","                        \"title\": story.get(\"title\"),\n","                        \"category\": assigned_cat,\n","                        \"score\": story.get(\"score\"),\n","                        \"num_comments\": story.get(\"descendants\", 0),\n","                        \"author\": story.get(\"by\"),\n","                        \"collected_at\": datetime.now().strftime(\"%Y-%m-%d %H:%M:%S\")\n","                    }\n","                    collected_data.append(story_info)\n","                    category_counts[cat_name] += 1\n","\n","            except Exception as e:\n","                print(f\"Error fetching story {s_id}: {e}\")\n","                continue\n","\n","        # A 2-second pause after the category loop ends\n","        time.sleep(2)\n","\n","    # 3. JSON flie saved\n","    date_str = datetime.now().strftime(\"%Y%m%d\")\n","    file_path = f\"data/trends_{date_str}.json\"\n","\n","    with open(file_path, 'w') as f:\n","        json.dump(collected_data, f, indent=4)\n","\n","    print(f\"Collected {len(collected_data)} stories. Saved to {file_path}\")\n","\n","except Exception as e:\n","    print(f\"An error occurred: {e}\")\n","\n"],"metadata":{"id":"EGs011ri_Qjo"},"execution_count":null,"outputs":[]}]}